option.value:
* {
    box-sizing: border-box;
}

:root {
    --bg: #f5f7fb;
    --surface: #ffffff;
    --text: #1f2937;
    --muted: #6b7280;
    --border: #dbe2ea;
    --primary: #2563eb;
    --primary-hover: #1d4ed8;
    --danger: #dc2626;
    --danger-hover: #b91c1c;
    --secondary: #6b7280;
    --secondary-hover: #4b5563;
    --success-soft: #ecfdf3;
    --success: #16a34a;
    --success-hover: #15803d;
}

body {
    margin: 0;
    font-family: "Inter", "Segoe UI", Roboto, Arial, sans-serif;
    background: var(--bg);
    color: var(--text);
    line-height: 1.45;
}

.landing-page {
    min-height: 100vh;
    padding: 24px;
    background: linear-gradient(135deg, #1d4ed8 0%, #3b82f6 40%, #93c5fd 100%);
    display: flex;
    align-items: center;
    justify-content: center;
}

.landing-hero {
    width: min(1100px, 100%);
    text-align: center;
    color: #fff;
}

.landing-hero-logomark {
    width: 80px;
    height: 80px;
    border-radius: 999px;
    margin: 0 auto 20px;
    border: 3px solid white;
    background: transparent;
    color: white;
    font-size: 2rem;
    font-weight: 800;
    display: flex;
    align-items: center;
    justify-content: center;
}

.landing-title {
    margin: 0;
    font-size: clamp(2.6rem, 7vw, 4.6rem);
    font-weight: 800;
    letter-spacing: -0.02em;
}

.landing-tagline {
    margin: 14px 0 24px;
    font-size: clamp(1rem, 2vw, 1.25rem);
    color: #e5efff;
}

.landing-cta {
    display: flex;
    justify-content: center;
    gap: 12px;
    flex-wrap: wrap;
    margin-bottom: 30px;
}

.landing-feature-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
    gap: 14px;
}

.landing-feature-card {
    background: rgba(255, 255, 255, 0.18);
    border: 1px solid rgba(255, 255, 255, 0.35);
    border-radius: 14px;
    padding: 18px;
    backdrop-filter: blur(8px);
}

.landing-feature-card h3 {
    margin: 6px 0 0;
    font-size: 1rem;
    color: #fff;
}

.feature-icon {
    font-size: 1.45rem;
}

.page {
    min-height: 100vh;
    padding: 24px 16px 40px;
}

.inner-page {
    background: #eef2ff;
}

.auth-page {
    min-height: 100vh;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 24px 16px;
    background: linear-gradient(135deg, #1a56db, #6eb6ff);
}

.auth-page .container {
    max-width: 560px;
}

.auth-shell {
    width: min(480px, 100%);
}

.auth-card {
    box-shadow: 0 14px 34px rgba(15, 23, 42, 0.12);
    border-radius: 14px;
}

.auth-brand {
    font-size: 1.6rem;
    font-weight: 800;
    margin-bottom: 4px;
    text-align: center;
}

.auth-subtitle {
    margin: 0 0 14px;
    color: var(--muted);
    text-align: center;
}

.auth-logomark {
    width: 52px;
    height: 52px;
    border-radius: 999px;
    margin: 0 auto 10px;
    background: linear-gradient(135deg, #1a56db, #2563eb);
    color: #fff;
    font-size: 1.5rem;
    font-weight: 800;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 8px 16px rgba(37, 99, 235, 0.35);
}

.auth-footer-link {
    text-align: center;
    margin-top: 14px;
}

.btn-block {
    width: 100%;
}

.password-hint {
    margin-top: 6px;
    font-size: 0.84rem;
}

.container {
    width: 100%;
    max-width: 980px;
    margin: 0 auto;
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 14px;
    padding: 24px;
    box-shadow: 0 8px 28px rgba(15, 23, 42, 0.06);
}

.app-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 12px;
    padding-bottom: 14px;
    border-bottom: 1px solid var(--border);
    margin-bottom: 20px;
}

.app-title {
    margin: 0;
    font-size: 1.35rem;
    font-weight: 700;
}

.app-subtitle {
    margin: 0;
    color: var(--muted);
    font-size: 0.95rem;
}

.nav {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    margin: 10px 0 18px;
}

h1,
h2,
h3 {
    margin: 0 0 14px;
}

p {
    margin: 10px 0;
}

a {
    color: var(--primary);
    text-decoration: none;
}

a:hover {
    text-decoration: underline;
}

.card {
    border: 1px solid var(--border);
    border-radius: 12px;
    background: #fff;
    padding: 16px;
    margin-bottom: 16px;
}

.enrolled-course-card {
    border-left: 4px solid #1a56db;
    transition: 0.2s ease;
}

.enrolled-course-card:hover {
    box-shadow: 0 8px 16px rgba(26, 86, 219, 0.15);
    transform: translateY(-2px);
}

.enrolled-course-card strong {
    color: #1a56db;
}

.hero {
    text-align: left;
}

.hero-title {
    margin: 0 0 8px;
    font-size: clamp(2rem, 4vw, 2.8rem);
    line-height: 1.15;
}

.hero-tagline {
    margin: 0 0 16px;
    color: var(--muted);
    font-size: 1.05rem;
}

.feature-list {
    margin: 14px 0 0;
    padding-left: 20px;
    color: var(--text);
}

.feature-list li {
    margin: 6px 0;
}

.form-grid {
    display: grid;
    gap: 12px;
    max-width: 520px;
}

label {
    display: block;
    font-weight: 600;
    margin-bottom: 6px;
}

input,
select,
textarea {
    width: 100%;
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 10px 12px;
    font-size: 0.95rem;
    background: #fff;
}

input:focus,
select:focus,
textarea:focus {
    outline: 2px solid #bfdbfe;
    border-color: #93c5fd;
}

.btn,
button {
    appearance: none;
    border: none;
    border-radius: 10px;
    padding: 10px 14px;
    font-size: 0.92rem;
    font-weight: 600;
    cursor: pointer;
    text-decoration: none;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 6px;
}

.btn-primary,
button,
.btn {
    background: var(--primary);
    color: #fff;
}

.btn-primary:hover,
button:hover,
.btn:hover {
    background: var(--primary-hover);
}

.btn-danger {
    background: var(--danger);
    color: #fff;
}

.btn-danger:hover {
    background: var(--danger-hover);
}

.btn-warning {
    background: #d97706;
    color: #fff;
}

.btn-warning:hover {
    background: #b45309;
}

.btn-success {
    background: var(--success);
    color: #fff;
}

.btn-success:hover {
    background: var(--success-hover);
}

.btn-secondary {
    background: var(--secondary);
    color: #fff;
}

.btn-secondary:hover {
    background: var(--secondary-hover);
}

.actions {
    display: flex;
    gap: 10px;
    flex-wrap: wrap;
    margin-top: 14px;
}

table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 10px;
    overflow: hidden;
    border-radius: 10px;
}

th,
td {
    border: 1px solid var(--border);
    padding: 10px;
    text-align: left;
    vertical-align: top;
}

th {
    background: #f8fafc;
}

.admin-courses-row {
    transition: 0.15s ease;
}

.admin-courses-row:hover {
    background: #eef2ff;
}

.admin-courses-row:nth-child(even) {
    background: #f8f9fa;
}

.admin-courses-row:nth-child(even):hover {
    background: #eef2ff;
}

.error-text,
.field-error {
    color: #b91c1c;
    font-size: 0.9rem;
    margin-top: 4px;
    display: block;
}

.helper-text {
    color: var(--muted);
    font-size: 0.92rem;
}

.empty-state {
    color: var(--muted);
    background: #f8fafc;
    border: 1px dashed var(--border);
    padding: 12px;
    border-radius: 10px;
}

.success-soft {
    background: var(--success-soft);
    border: 1px solid #a7f3d0;
    border-radius: 10px;
    padding: 10px;
}

.inline-form {
    display: inline;
}

/* ========== Flash alert banners ========== */
.alert {
    padding: 12px 16px;
    border-radius: 10px;
    margin-bottom: 16px;
    font-weight: 500;
    display: flex;
    align-items: center;
    gap: 8px;
}

.alert-success {
    background: #ecfdf5;
    border: 1px solid #a7f3d0;
    color: #065f46;
}

.alert-error {
    background: #fef2f2;
    border: 1px solid #fecaca;
    color: #991b1b;
}

.alert-warning {
    background: #fffbeb;
    border: 1px solid #fde68a;
    color: #92400e;
}

.role-badge {
    display: inline-block;
    margin-left: 8px;
    padding: 3px 8px;
    border-radius: 999px;
    font-size: 0.75rem;
    vertical-align: middle;
    font-weight: 700;
}

.role-admin {
    background: #dbeafe;
    color: #1d4ed8;
}

.role-student {
    background: #dcfce7;
    color: #15803d;
}

.stats-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    gap: 12px;
    margin: 10px 0 16px;
}

.stat-card {
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 12px;
    background: #f8fafc;
}

.stat-label {
    font-size: 0.85rem;
    color: var(--muted);
}

.stat-value {
    font-size: 1.4rem;
    font-weight: 700;
    margin-top: 4px;
}

.course-card-grid {
    display: grid;
    gap: 12px;
    grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
}

.course-student-card {
    border: 1px solid var(--border);
    border-left: 4px solid #1a56db;
    border-radius: 12px;
    padding: 14px;
    background: #fff;
    transition: 0.2s ease;
}

.course-student-card:hover {
    box-shadow: 0 8px 16px rgba(26, 86, 219, 0.15);
    transform: translateY(-2px);
}

.course-code {
    font-size: 1.15rem;
    font-weight: 800;
    margin-bottom: 6px;
    color: #1a56db;
}

.course-name {
    font-weight: 600;
    margin-bottom: 6px;
}

.course-prof {
    color: var(--muted);
    margin-bottom: 12px;
}

.btn:disabled,
button:disabled {
    opacity: 0.7;
    cursor: not-allowed;
}

.toast-container {
    position: fixed;
    top: 16px;
    right: 16px;
    display: grid;
    gap: 10px;
    z-index: 1300;
    width: min(360px, calc(100% - 24px));
}

.toast-container-auth {
    position: static;
    width: 100%;
    margin-bottom: 12px;
}

.toast {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 10px;
    padding: 12px 14px;
    border-radius: 10px;
    border: 1px solid transparent;
    box-shadow: 0 8px 20px rgba(15, 23, 42, 0.12);
    background: #fff;
}

.toast-success {
    background: #ecfdf5;
    border-color: #a7f3d0;
    color: #065f46;
}

.toast-warning {
    background: #fffbeb;
    border-color: #fde68a;
    color: #92400e;
}

.toast-error {
    background: #fef2f2;
    border-color: #fecaca;
    color: #991b1b;
}

.toast-close {
    border: none;
    background: transparent;
    color: inherit;
    font-size: 1.25rem;
    line-height: 1;
    cursor: pointer;
    padding: 0;
}

.toast-hide {
    opacity: 0;
    transform: translateY(-8px);
    transition: 0.25s ease;
}

.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(15, 23, 42, 0.55);
    display: none;
    align-items: center;
    justify-content: center;
    padding: 16px;
    z-index: 1400;
}

.modal-overlay.show {
    display: flex;
}

.modal-card {
    background: #fff;
    width: min(440px, 100%);
    border-radius: 12px;
    padding: 18px;
    border: 1px solid var(--border);
    box-shadow: 0 18px 36px rgba(15, 23, 42, 0.22);
}

/* ========== Active nav button ========== */
.btn.active,
a.btn.active {
    background: var(--primary);
    color: #fff;
    box-shadow: inset 0 0 0 2px rgba(0, 0, 0, 0.12);
    text-decoration: none;
}

@media (max-width: 768px) {
    .container {
        padding: 16px;
    }

    .app-header {
        flex-direction: column;
        align-items: flex-start;
    }

    .nav,
    .actions {
        width: 100%;
    }

    .nav .btn,
    .actions .btn,
    .actions button,
    .form-grid button {
        width: 100%;
    }

    th,
    td {
        font-size: 0.9rem;
    }
}

