    color: #b91c1c;
    font-size: 0.9rem;
    margin-top: 4px;
    display: block;
}

.helper-text {
    color: var(--muted);
    font-size: 0.92rem;
}

.empty-state {
    color: var(--muted);
    background: #f8fafc;
    border: 1px dashed var(--border);
    padding: 12px;
    border-radius: 10px;
}

.success-soft {
    background: var(--success-soft);
    border: 1px solid #a7f3d0;
    border-radius: 10px;
    padding: 10px;
}

.inline-form {
    display: inline;
}

/* ========== Flash alert banners ========== */
.alert {
    padding: 12px 16px;
    border-radius: 10px;
    margin-bottom: 16px;
    font-weight: 500;
    display: flex;
    align-items: center;
    gap: 8px;
}

.alert-success {
    background: #ecfdf5;
    border: 1px solid #a7f3d0;
    color: #065f46;
}

.alert-error {
    background: #fef2f2;
    border: 1px solid #fecaca;
    color: #991b1b;
}

.alert-warning {
    background: #fffbeb;
    border: 1px solid #fde68a;
    color: #92400e;
}

.role-badge {
    display: inline-block;
    margin-left: 8px;
    padding: 3px 8px;
    border-radius: 999px;
    font-size: 0.75rem;
    vertical-align: middle;
    font-weight: 700;
}

.role-admin {
    background: #dbeafe;
    color: #1d4ed8;
}

.role-student {
    background: #dcfce7;
    color: #15803d;
}

.stats-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    gap: 12px;
    margin: 10px 0 16px;
}

.stat-card {
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 12px;
    background: #f8fafc;
}

.stat-label {
    font-size: 0.85rem;
    color: var(--muted);
}

.stat-value {
    font-size: 1.4rem;
    font-weight: 700;
    margin-top: 4px;
}

.course-card-grid {
    display: grid;
    gap: 12px;
    grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
}

.course-student-card {
    border: 1px solid var(--border);
    border-left: 4px solid #1a56db;
    border-radius: 12px;
    padding: 14px;
    background: #fff;
    transition: 0.2s ease;
}

.course-student-card:hover {
    box-shadow: 0 8px 16px rgba(26, 86, 219, 0.15);
    transform: translateY(-2px);
}

.course-code {
    font-size: 1.15rem;
    font-weight: 800;
    margin-bottom: 6px;
    color: #1a56db;
}

.course-name {
    font-weight: 600;
    margin-bottom: 6px;
}

.course-prof {
    color: var(--muted);
    margin-bottom: 12px;
}

.btn:disabled,
button:disabled {
    opacity: 0.7;
    cursor: not-allowed;
}

.toast-container {
    position: fixed;
    top: 16px;
    right: 16px;
    display: grid;
    gap: 10px;
    z-index: 1300;
    width: min(360px, calc(100% - 24px));
}

.toast-container-auth {
    position: static;
    width: 100%;
    margin-bottom: 12px;
}

.toast {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 10px;
    padding: 12px 14px;
    border-radius: 10px;
    border: 1px solid transparent;
    box-shadow: 0 8px 20px rgba(15, 23, 42, 0.12);
    background: #fff;
}

.toast-success {
    background: #ecfdf5;
    border-color: #a7f3d0;
    color: #065f46;
}

.toast-warning {
    background: #fffbeb;
    border-color: #fde68a;
    color: #92400e;
}

.toast-error {
    background: #fef2f2;
    border-color: #fecaca;
    color: #991b1b;
}

.toast-close {
    border: none;
    background: transparent;
    color: inherit;
    font-size: 1.25rem;
    line-height: 1;
    cursor: pointer;
    padding: 0;
}

.toast-hide {
    opacity: 0;
    transform: translateY(-8px);
    transition: 0.25s ease;
}

.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(15, 23, 42, 0.55);
    display: none;
    align-items: center;
    justify-content: center;
    padding: 16px;
    z-index: 1400;
}

.modal-overlay.show {
    display: flex;
}

.modal-card {
    background: #fff;
    width: min(440px, 100%);
    border-radius: 12px;
    padding: 18px;
    border: 1px solid var(--border);
    box-shadow: 0 18px 36px rgba(15, 23, 42, 0.22);
}

/* ========== Active nav button ========== */
.btn.active,
a.btn.active {
    background: var(--primary);
    color: #fff;
    box-shadow: inset 0 0 0 2px rgba(0, 0, 0, 0.12);
    text-decoration: none;
}

@media (max-width: 768px) {
    .container {
        padding: 16px;
    }

    .app-header {
        flex-direction: column;
        align-items: flex-start;
    }

    .nav,
    .actions {
        width: 100%;
    }

    .nav .btn,
    .actions .btn,
    .actions button,
    .form-grid button {
        width: 100%;
    }

    th,
    td {
        font-size: 0.9rem;
    }
}
